            variant {
              id
            }
          }
        }
      }
    }
    returns(first: 50) {
      nodes {
        id
        name
        status
        totalQuantity
        returnLineItems(first: 50) {
          nodes {
            ... on ReturnLineItem {
              id
              quantity
              fulfillmentLineItem {
                id
              }
            }
          }
        }
      }
    }
  }
}

